	signal?: AbortSignal,
	onUpdate?: (update: any) => void,
): Promise<Array<{ specialist: string; output: string; error?: string }>> {
	const concurrency = Math.min(MAX_PARALLEL, tasks.length);
	const results: Array<{ specialist: string; output: string; error?: string }> = new Array(tasks.length);
	let nextIndex = 0;

	const workers = Array(concurrency).fill(null).map(async () => {
		while (nextIndex < tasks.length) {
			const i = nextIndex++;
			const { specialist, task } = tasks[i];
			try {
				const result = await runSubagent(specialist, task, cwd, parentCtx, signal, onUpdate);
				results[i] = { specialist: specialist.name, output: result.output };
			} catch (error) {
				results[i] = {
					specialist: specialist.name,
					output: "",
					error: error instanceof Error ? error.message : String(error),
				};
			}
		}
	});

	await Promise.all(workers);
	return results;
}

