// ── Tool: delegate — Single task to one specialist ────────────────────

pi.registerTool({
	name: "delegate",
	label: "Delegate Task",
	description: `Delegate a task to a specialist subagent. Runs in an isolated in-process session with its own system prompt and tools. Returns the subagent's output.`,
	parameters: Type.Object({
		specialist: Type.String({
			description: "Which specialist to use: scout, coder, reviewer, researcher, writer",
		}),
		task: Type.String({
			description: "The task to delegate. Be specific and include all necessary context.",
		}),
	}),
	async execute(toolCallId, params, signal, onUpdate, ctx) {
		const specialist = SPECIALISTS[params.specialist];
		if (!specialist) {
			const available = Object.keys(SPECIALISTS).join(", ");
			return {
				content: [{ type: "text", text: `Unknown specialist: "${params.specialist}". Available: ${available}` }],
				details: {},
			};
		}

		// Reset and create fresh orchestrator activity
		resetOrchestratorActivity();
		const activity = getOrchestratorActivity(params.task);
		addOrchestratorStep(activity, params.task);

		// Stream orchestrator progress (cache-safe: onUpdate is display-only)
		onUpdate?.({
			content: [{ type: "text", text: renderOrchestratorActivity(activity, orchestratorGoal) }],
			details: { specialist: specialist.name, task: params.task, status: "running" },
		});

		const result = await runSubagent(specialist, params.task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate, activity);

		// Mark step complete
		completeOrchestratorStep(activity);

		// Final update with completed step
		onUpdate?.({
			content: [{ type: "text", text: renderOrchestratorActivity(activity, orchestratorGoal) }],
			details: { specialist: specialist.name, task: params.task, status: "done" },
		});

		return {
			content: [{ type: "text", text: result.output }],
			details: {
				specialist: specialist.name,
				task: params.task,
				status: "done",
				turns: result.turns,
				outputLength: result.output.length,
			},
		};
	},
});

