// ── Tool: delegate — Single, parallel, or chain mode ──────────────────

pi.registerTool({
	name: "delegate",
	label: "delegate",
	description: `Delegate work to specialist subagents. Three modes:\n- Single: { specialist, task }\n- Parallel: { tasks: [{specialist, task}, ...] }\n- Chain: { steps: [{specialist, task}, ...] } with {previous} placeholder`,
	parameters: Type.Object({
		specialist: Type.Optional(Type.String({
			description: "Specialist: scout, coder, reviewer, researcher, writer",
		})),
		task: Type.Optional(Type.String({
			description: "Task description",
		})),
		tasks: Type.Optional(Type.Array(
			Type.Object({
				specialist: Type.String({ description: "Specialist name" }),
				task: Type.String({ description: "Task description" }),
			}),
			{ description: "Parallel mode: run these tasks simultaneously" },
		)),
		steps: Type.Optional(Type.Array(
			Type.Object({
				specialist: Type.String({ description: "Specialist name" }),
				task: Type.String({ description: "Task. Use {previous} for prior output." }),
			}),
			{ description: "Chain mode: run sequentially, pass output to next" },
		)),
	}),

	// ── Render: what shows when tool is invoked ──
	renderCall(args, theme, _context) {
		if (args.tasks) {
			const names = args.tasks.map((t: any) => t.specialist).join(", ");
			return new Text(theme.fg("toolTitle", theme.bold(`→ parallel [${args.tasks.length}] `)) + theme.fg("dim", names), 0, 0);
		}
		if (args.steps) {
			const names = args.steps.map((s: any) => s.specialist).join(" → ");
			return new Text(theme.fg("toolTitle", theme.bold(`→ chain `)) + theme.fg("dim", names), 0, 0);
		}
		return new Text(theme.fg("toolTitle", theme.bold(`→ `)) + theme.fg("accent", args.specialist || "?"), 0, 0);
	},

	// ── Render: what shows during/after execution ──
	renderResult(result, { isPartial, expanded }, theme, _context) {
		if (isPartial) {
			const details = result.details as any;
			if (details?.status === "running" && details?.specialist) {
				return new Text(theme.fg("warning", `⠋ ${details.specialist} running...`), 0, 0);
			}
			return new Text(theme.fg("warning", "⠋ working..."), 0, 0);
		}

		const details = result.details as any;
		const content = result.content?.[0];
		const text = content?.type === "text" ? content.text : "";

		// Single mode
		if (details?.specialist) {
			const dur = details.turns ? ` (${details.turns} turns)` : "";
			let out = theme.fg("success", `✓ ${details.specialist}`) + theme.fg("dim", dur);
			if (expanded && text) {
				const lines = text.split("\n").slice(0, 10);
				for (const line of lines) {
					out += `\n${theme.fg("dim", "  " + line)}`;
				}
				if (text.split("\n").length > 10) {
					out += `\n${theme.fg("muted", "  ...")}`;
				}
			}
			return new Text(out, 0, 0);
		}

		// Parallel mode
		if (details?.results) {
			const ok = details.results.filter((r: any) => !r.error).length;
			const total = details.results.length;
			let out = theme.fg("success", `✓ ${ok}/${total} completed`);
			if (expanded) {
				for (const r of details.results) {
					const icon = r.error ? theme.fg("error", "✗") : theme.fg("success", "✓");
					out += `\n${icon} ${r.specialist}`;
				}
			}
			return new Text(out, 0, 0);
		}

		// Chain mode
		if (details?.steps) {
			let out = theme.fg("success", `✓ ${details.steps} steps completed`);
			if (expanded && text) {
				const lines = text.split("\n").slice(0, 10);
				for (const line of lines) {
					out += `\n${theme.fg("dim", "  " + line)}`;
				}
			}
			return new Text(out, 0, 0);
		}

		return new Text(theme.fg("success", "✓ done"), 0, 0);
	},

	async execute(toolCallId, params, signal, onUpdate, ctx) {
		// ── Parallel mode ──
		if (params.tasks) {
			if (params.tasks.length > MAX_PARALLEL) {
				return { content: [{ type: "text", text: `Too many tasks (${params.tasks.length}). Max: ${MAX_PARALLEL}` }], details: {} };
			}

			const resolved = params.tasks
				.map((t) => {
					const spec = SPECIALISTS[t.specialist];
					if (!spec) return null;
					return { specialist: spec, task: t.task };
				})
				.filter(Boolean) as Array<{ specialist: Specialist; task: string }>;

			if (resolved.length === 0) {
				return { content: [{ type: "text", text: "No valid specialists found." }], details: {} };
			}

			resetOrchestratorActivity();

			// Stream status per specialist
			let running = 0;
			const updateStatus = () => {
				const names = resolved.map((r, i) => {
					const done = results[i]?.output !== undefined;
					return done ? theme.fg("success", r.specialist.name) : theme.fg("warning", r.specialist.name);
				}).join(" ");
				onUpdate?.({
					content: [{ type: "text", text: `⠋ ${names}` }],
					details: { status: "running", specialist: names },
				});
			};

			const results: Array<{ specialist: string; output: string; error?: string }> = new Array(resolved.length);

			// Run in parallel with status updates
			const promises = resolved.map(async (r, i) => {
				running++;
				updateStatus();
				try {
					const result = await runSubagent(r.specialist, r.task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate);
					results[i] = { specialist: r.specialist.name, output: result.output };
				} catch (error) {
					results[i] = { specialist: r.specialist.name, output: "", error: error instanceof Error ? error.message : String(error) };
				}
				running--;
				updateStatus();
			});

			await Promise.all(promises);

			const output = results
				.map((r) => `### [${r.specialist}] ${r.error ? "ERROR" : "OK"}\n\n${r.output}`)
				.join("\n\n---\n\n");

			return {
				content: [{ type: "text", text: output }],
				details: { status: "done", results: results.map((r) => ({ specialist: r.specialist, outputLength: r.output.length, error: r.error })) },
			};
		}

		// ── Chain mode ──
		if (params.steps) {
			const results: Array<{ step: number; specialist: string; output: string; error?: string }> = [];
			let previousOutput = "";

			resetOrchestratorActivity();

			for (let i = 0; i < params.steps.length; i++) {
				const step = params.steps[i];
				const specialist = SPECIALISTS[step.specialist];

				if (!specialist) {
					results.push({ step: i + 1, specialist: step.specialist, output: "", error: `Unknown specialist: "${step.specialist}"` });
					break;
				}

				const task = step.task.replace(/\{previous\}/g, previousOutput);

				onUpdate?.({
					content: [{ type: "text", text: `⠋ ${specialist.name}...` }],
					details: { status: "running", specialist: specialist.name },
				});

				const result = await runSubagent(specialist, task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate);
				previousOutput = result.output;

				results.push({ step: i + 1, specialist: specialist.name, output: result.output });

				if (result.output.startsWith("[error]")) break;
			}

			const output = results
				.map((r) => `### Step ${r.step}: [${r.specialist}] ${r.error ? "ERROR" : "OK"}\n\n${r.output}`)
				.join("\n\n---\n\n");

			return {
				content: [{ type: "text", text: output }],
				details: { status: "done", steps: results.length, results },
			};
		}

		// ── Single mode ──
		if (!params.specialist || !params.task) {
			return { content: [{ type: "text", text: "Provide specialist+task, tasks[], or steps[]" }], details: {} };
		}

		const specialist = SPECIALISTS[params.specialist];
		if (!specialist) {
			const available = Object.keys(SPECIALISTS).join(", ");
			return { content: [{ type: "text", text: `Unknown specialist: "${params.specialist}". Available: ${available}` }], details: {} };
		}

		resetOrchestratorActivity();

		onUpdate?.({
			content: [{ type: "text", text: `⠋ ${specialist.name}...` }],
			details: { status: "running", specialist: specialist.name },
		});

		const result = await runSubagent(specialist, params.task, ctx.cwd, { modelRegistry: ctx.modelRegistry, model: ctx.model }, signal, onUpdate);

		return {
			content: [{ type: "text", text: result.output }],
			details: { specialist: specialist.name, task: params.task, status: "done", turns: result.turns, outputLength: result.output.length },
		};
	},
});

